mapper.select:
SELECT p.id AS post_id, p.user_id, u.nickname, u.profile_image_url, p.location_id, l.si_do, l.si_gun_gu, p.content, p.created_at, CASE WHEN pl.user_id IS NULL THEN 'N' ELSE 'Y' END AS likeYN, CASE WHEN p.user_id = #{userId} THEN TRUE ELSE FALSE END AS isMine, (SELECT COUNT(*) FROM post_likes WHERE post_id = p.id) AS likeCount, (SELECT COUNT(*) FROM posts WHERE parent_id = p.id) AS commentCount, p.status FROM posts p LEFT JOIN users u ON u.id = p.user_id LEFT JOIN locations l ON l.id = p.location_id LEFT JOIN post_likes pl ON pl.post_id = p.id AND pl.user_id = #{userId} WHERE p.depth = 0 AND p.status = 'ACTIVE'
AND p.user_id = #{filterUserId}
AND p.location_id = #{locationId}
ORDER BY p.id DESC LIMIT #{size} OFFSET #{offset};

SELECT post_id, image_url AS url, sort_order FROM post_images WHERE post_id IN
#{id}
ORDER BY sort_order ASC

SELECT pet.post_id, et.id, et.emoji, et.name FROM post_emotion_tag pet JOIN emotion_tags et ON et.id = pet.emotion_id WHERE pet.post_id IN
#{id}
ORDER BY et.id ASC

mapper.update:
UPDATE posts
content = #{content}, location_id = #{locationId},
WHERE id = #{postId}

choose.when:
INSERT INTO posts (user_id, parent_id, content, depth)
SELECT #{userId}, #{parentId}, #{content}, depth + 1
FROM posts WHERE id = #{parentId}
